```python
import math

def is_prime(n: int) -> bool:
    if n <= 1:
        return False
    if n in (2, 3):        # Special case handling
        return True
    if n % 2 == 0:
        return False

    # Only check up to the square root of n and for odd divisors
    for p in range(3, int(math.isqrt(n)) + 1, 2):
        if n % p == 0:
            return False  # n is not prime

    return True  # n is prime

# or with an optimized check for square roots directly (without `math.isqrt` - which is available from Python 3.8+)

def optimized_is_prime(n: int):
    if n <= 1:
        return False
    if n in (2, 3):
        return True
    if n % 2 == 0:
        return False

    sqrt_n = int(n**0.5)
    for p in range(3, sqrt_n + 1, 2):
        if n % p == 0: 
            return False

    return True 

# Complexity analysis: Both functions run in O(sqrt(n)) time on average
```

